import{_ as r,o as t,c as s,a6 as p,kf as o,kg as n,kh as i,ki as e,kj as g,ii as l,kk as _,kl as m,km as d,kr as c,ks as h,kt as k,fI as f,fZ as b,kw as x}from"./chunks/framework.UYVGz2W_.js";const A=JSON.parse('{"title":"ステータスとフィードバック","description":"","frontmatter":{},"headers":[],"relativePath":"ja/status/index.md","filePath":"ja/status/index.md"}'),u={name:"ja/status/index.md"};function P(w,a,T,S,C,$){return t(),s("div",null,[...a[0]||(a[0]=[p('<h1 id="ステータスとフィードバック" tabindex="-1">ステータスとフィードバック <a class="header-anchor" href="#ステータスとフィードバック" aria-label="Permalink to “ステータスとフィードバック”">​</a></h1><p>Kitsuでは、ステータスはタスクの現在の状態や進捗状況を示す指標となります。現在のステータスを一目で簡単に確認でき、ステータスが変更された際にチームメンバーに更新情報を伝えるコメントを追加できます。</p><h2 id="コメントパネル" tabindex="-1">コメントパネル <a class="header-anchor" href="#コメントパネル" aria-label="Permalink to “コメントパネル”">​</a></h2><p>タスクのステータスを変更したりコメントを追加するには、タスクのステータスをクリックします。</p><p><img src="'+o+'" alt="ショットのステータス"></p><p>右側にパネルが表示され、コメントの書き込み、ステータスの変更、ファイルの添付を行うことができます。</p><p><img src="'+n+'" alt="コメントパネル"></p><p>コメントパネル<strong>は</strong>、2つのタブに分かれています。</p><ul><li>コメントを投稿</li><li>リビジョンを公開</li></ul><p><strong>ステータス</strong>は、<strong>コメントを投稿</strong>タブから変更できます。</p><p>コメントでは、プレーンテキストをシンプルかつ読みやすくフォーマットするためのマークアップ言語である <strong>Markdown</strong> を使用できます。これにより、ユーザーは見出し、リスト、太字や斜体、リンクなど、基本的なフォーマット要素を追加することができます。特定の構文については、Markdownガイドのウェブサイトを参照してください：<a href="https://www.markdownguide.org/basic-syntax/" target="_blank" rel="noreferrer">Markdown Guide</a>。</p><h3 id="チームメンバーのタグ付け" tabindex="-1">チームメンバーのタグ付け <a class="header-anchor" href="#チームメンバーのタグ付け" aria-label="Permalink to “チームメンバーのタグ付け”">​</a></h3><p>コメント内でチームメンバーを<strong>タグ付け</strong>して、直接通知することもできます。これを行うには、<code>@</code>と入力すると、チームメンバーのリストを含むサブメニューが開きます。通知したいメンバーを選択し、コメントを送信すると、そのメンバーに通知が届きます。</p><p><img src="'+i+'" alt="誰かをタグ付け"></p><p>「@」に続けて部署名を入力することで、部署全体に<strong>タグ付け</strong>することもできます。</p><p><img src="'+e+'" alt="部署にタグ付け"></p><h3 id="チェックリストの追加" tabindex="-1">チェックリストの追加 <a class="header-anchor" href="#チェックリストの追加" aria-label="Permalink to “チェックリストの追加”">​</a></h3><p>独自のタスクに値しないさまざまな項目を追跡するために、チェックリスト項目も追加できます。<strong>チェックリスト</strong>をコメントに追加するには、<strong>[チェックリストを追加]</strong>ボタンをクリックします。チェックリストの最初の項目が表示されます。</p><p><img src="'+g+'" alt="チェックリストを追加"></p><p><strong>Enter</strong>キーを押すか、ボタンを再度クリックしてチェックリスト項目を追加し、各項目に名前を付けます。</p><p><img src="'+l+'" alt="チェックリスト"></p><h3 id="添付ファイルの追加" tabindex="-1">添付ファイルの追加 <a class="header-anchor" href="#添付ファイルの追加" aria-label="Permalink to “添付ファイルの追加”">​</a></h3><p>画像としてファイルを添付するには、<strong>添付ファイルを追加</strong>ボタンをクリックします。</p><p><img src="'+_+'" alt="添付ファイルの追加（簡易）"></p><p><strong>ハードドライブからファイルを選択</strong>するか、<strong>スクリーンショット</strong>を貼り付けます。</p><p><img src="'+m+'" alt="添付のスナップショット"></p><p><strong>添付ファイルとして追加</strong>をクリックして添付ファイルを検証します。</p><p>次に、ドロップダウンメニューからタスクのステータスを変更する<strong>ステータス</strong>を選択します。</p><p><img src="'+d+'" alt="ステータスリスト"></p><p>最後に、<strong>投稿</strong>ボタンをクリックしてコメントとステータスの更新を送信します。</p><p>ステータスの一括変更 複数のステータスを一度に更新 複数のタスクのステータスを一度に変更することもできます。</p><p>Ctrl/CmdキーまたはShiftキーを押しながら、複数のショットまたはアセットを選択し、対象とするタスクを選択します。</p><p>次に、アクションメニューの「ステータス変更」セクションに移動します。</p><p><img src="'+c+'" alt="アクションメニューのステータス"></p><p>選択したタスクの新しいステータスを選択します (1)。 選択したすべてのタスクにコメントを追加することもできます (2)。 <strong>Confirm</strong> ボタンで新しいステータスを保存します。</p><p><img src="'+h+'" alt="バッチごとのステータスの変更"></p><p><img src="'+k+'" alt="メタデータカラムのソート順"></p><h2 id="アーティストボードのステータス" tabindex="-1">アーティストボードのステータス <a class="header-anchor" href="#アーティストボードのステータス" aria-label="Permalink to “アーティストボードのステータス”">​</a></h2><h3 id="アーティストボードページで使用されるステータスのカスタマイズ" tabindex="-1">アーティストボードページで使用されるステータスのカスタマイズ <a class="header-anchor" href="#アーティストボードページで使用されるステータスのカスタマイズ" aria-label="Permalink to “アーティストボードページで使用されるステータスのカスタマイズ”">​</a></h3><p>タスクをアーティストに割り当てると、アーティストがログインした際に、そのタスクがアーティストのToDoページに表示されます。</p><p>デフォルトの表示では、タスクは従来のリスト形式で表示されますが、ボード形式で表示することもできます。各<strong>ステータス</strong>は列で表され、割り当てられたタスクは、タスクの進行に合わせてステータスからステータスへとドラッグできるカードとして表示されます。</p><p>ボード形式をカスタマイズするには、制作の設定ページにアクセスします。</p><p><img src="'+f+'" alt="設定ページ"></p><p>次に、[タスクのステータス] タブに移動します。 お客様の制作で使用されているステータスのリストが表示されます。</p><p>これらのステータスがボードページの列として使用されます。 ステータスをドラッグして移動させると、ボードビューに表示される順序を変更することができます。</p><p><img src="'+b+'" alt="ページのステータスの順序設定"></p><p>次に、<strong>[ボードのステータス]</strong>セクションをクリックします。</p><p><img src="'+x+'" alt="ページのステータスボードの設定"></p><p>ここでは、<strong>[ボード]</strong>ページでどの権限ロールがどのステータスを表示できるかをカスタマイズできます。</p><p>このビューにアクセスするには、「マイタスク」ページから「<strong>ボード</strong>」タブを選択します。 チームメンバーには、以下のようなページが表示されます</p><p>！<a href="../img/getting-started/artist_board_page.png">アーティストボードページ</a></p><p>::: ヒント ボードビューに表示されるステータスのカスタマイズは、権限ロールごとに設定されます。 個々のユーザーごとにカスタマイズすることはできません。 :::</p>',52)])])}const D=r(u,[["render",P]]);export{A as __pageData,D as default};
